create table paymob_callback_log (
    order_id    number,
    status      varchar2(30 byte),
    raw_body    clob,
    created_at  timestamp(6) with local time zone default sysdate,
    created_by  varchar2(300 byte),
    callback_id number generated by default on null as identity not null enable
);

create unique index paymob_callback_log_con on
    paymob_callback_log (
        callback_id
    );

alter table paymob_callback_log
    add constraint paymob_callback_log_con primary key ( callback_id )
        using index paymob_callback_log_con enable;

